// ============================================================================
// VtDictionary ↔ Python dict
// ============================================================================

/// Convert a Rust `Dictionary` to a Python `dict` (recursive).
pub fn dict_to_py(py: Python<'_>, d: &Dictionary) -> PyResult<Py<PyAny>> {
    let dict = PyDict::new(py);
    for (k, v) in d.iter() {
        dict.set_item(k, value_to_py(py, v)?)?;
    }
    Ok(dict.into_any().unbind())
}

/// Convert a Python object to a Rust `Value`.
///
/// Matches C++ `VtValue` / `TfPyConvert` behavior: typed arrays (`point3f[]`, `int[]`, …),
/// not `VtValue`-of-`VtValue` for homogeneous sequences.
pub fn py_to_value(obj: &Bound<'_, PyAny>) -> PyResult<Value> {
    if obj.is_none() {
        return Ok(Value::empty());
    }
    // bool before int (Python bool subclasses int)
    if let Ok(b) = obj.extract::<bool>() {
        return Ok(Value::new(b));
    }
    if let Ok(i) = obj.extract::<i64>() {
        if i >= i64::from(i32::MIN) && i <= i64::from(i32::MAX) {
            return Ok(Value::new(i as i32));
        }
        return Ok(Value::new(i));
    }
    if let Ok(u) = obj.extract::<u64>() {
        return Ok(Value::new(u));
    }
    if let Ok(f) = obj.extract::<f64>() {
        return Ok(Value::from_f64(f));
    }
    if let Ok(m) = obj.extract::<PyRef<PyMatrix4d>>() {
        return Ok(Value::from_no_hash(m.0));
    }
    // Gf.Vec3d/f must win over Vec<f64>: otherwise xformOp stores double[3] and
    // UsdGeomXformOp::GetOpTransform fails to downcast → identity local matrix.
    if let Ok(v) = obj.extract::<PyRef<PyVec3d>>() {
        return Ok(Value::from_no_hash(v.0));
    }
    if let Ok(v) = obj.extract::<PyRef<PyVec3f>>() {
        return Ok(Value::from_no_hash(v.0));
    }
    if let Ok(v) = obj.extract::<PyRef<PyVec2f>>() {
        return Ok(Value::from_no_hash(v.0));
    }
    if let Ok(s) = obj.extract::<String>() {
        return Ok(Value::new(s));
    }
    if let Ok(d) = obj.cast::<PyDict>() {
        return Ok(Value::from_dictionary(py_dict_to_dict(d)?.to_hash_map()));
    }
    // Already materialized Vt arrays / wrappers
    if let Ok(a) = obj.extract::<PyRef<PyVec3fArray>>() {
        return Ok(Value::from_no_hash(a.inner.clone()));
    }
    if let Ok(a) = obj.extract::<PyRef<PyVec4fArray>>() {
        return Ok(Value::from_no_hash(a.inner.clone()));
    }
    if let Ok(a) = obj.extract::<PyRef<PyIntArray>>() {
        return Ok(Value::from(a.inner.clone()));
    }
    // Homogeneous sequences (before `Vec<f64>` — otherwise `[0]` becomes `[0.0f64]`).
    if let Some(v) = seq_to_vec3f_array_value(obj)? {
        return Ok(v);
    }
    if let Some(v) = seq_to_vec4f_vec_value(obj)? {
        return Ok(v);
    }
    if let Some(v) = seq_to_i32_vec_value(obj)? {
        return Ok(v);
    }
    if let Ok(v) = obj.extract::<Vec<f64>>() {
        return Ok(Value::from_no_hash(v));
    }
    if let Ok(v) = obj.extract::<Vec<String>>() {
        return Ok(Value::from(v));
    }
    // Handle Python lists — only as a last resort: `vector[VtValue]` (rare in USD attrs)
    if let Ok(list) = obj.cast::<PyList>() {
        let mut values = Vec::new();
        for item in list.iter() {
            values.push(py_to_value(&item)?);
        }
        return Ok(Value::new(values));
    }
    if let Ok(tuple) = obj.cast::<PyTuple>() {
        let mut values = Vec::new();
        for item in tuple.iter() {
            values.push(py_to_value(&item)?);
        }
        return Ok(Value::new(values));
    }
    Err(PyValueError::new_err(format!(
        "Cannot convert Python object of type '{}' to Vt.Value",
        obj.get_type().name()?
    )))
}

/// `[Gf.Vec3f, ...]` or `[(f,f,f), ...]` → `VtArray<GfVec3f>` inside [`Value`].
fn seq_to_vec3f_array_value(obj: &Bound<'_, PyAny>) -> PyResult<Option<Value>> {
    let push_elem = |item: Bound<'_, PyAny>| -> PyResult<Option<usd_gf::Vec3f>> {
        if let Ok(p) = item.extract::<PyRef<PyVec3f>>() {
            return Ok(Some(p.0));
        }
        if let Ok((x, y, z)) = item.extract::<(f32, f32, f32)>() {
            return Ok(Some(usd_gf::Vec3f::new(x, y, z)));
        }
        Ok(None)
    };

    let mut arr = Array::<usd_gf::Vec3f>::new();
    if let Ok(list) = obj.cast::<PyList>() {
        let n = list.len();
        if n == 0 {
            return Ok(None);
        }
        for i in 0..n {
            let item = list.get_item(i)?;
            let Some(v) = push_elem(item)? else {
                return Ok(None);
            };
            arr.push(v);
        }
        return Ok(Some(Value::from_no_hash(arr)));
    }
    if let Ok(tuple) = obj.cast::<PyTuple>() {
        let n = tuple.len();
        if n == 0 {
            return Ok(None);
        }
        for i in 0..n {
            let item = tuple.get_item(i)?;
            let Some(v) = push_elem(item)? else {
                return Ok(None);
            };
            arr.push(v);
        }
        return Ok(Some(Value::from_no_hash(arr)));
    }
    Ok(None)
}

/// `[(x,y,z,w), ...]` / `[Gf.Vec4f, ...]` → `vector[GfVec4f]` for `float4[]` attrs.
fn seq_to_vec4f_vec_value(obj: &Bound<'_, PyAny>) -> PyResult<Option<Value>> {
    let push_elem = |item: Bound<'_, PyAny>| -> PyResult<Option<usd_gf::Vec4f>> {
        if let Ok(p) = item.extract::<PyRef<PyVec4f>>() {
            return Ok(Some(p.0));
        }
        if let Ok((x, y, z, w)) = item.extract::<(f32, f32, f32, f32)>() {
            return Ok(Some(usd_gf::Vec4f::new(x, y, z, w)));
        }
        if let Ok((x, y, z, w)) = item.extract::<(i32, i32, i32, i32)>() {
            return Ok(Some(usd_gf::Vec4f::new(
                x as f32, y as f32, z as f32, w as f32,
            )));
        }
        if let Ok(v) = item.extract::<Vec<f64>>() {
            if v.len() == 4 {
                return Ok(Some(usd_gf::Vec4f::new(
                    v[0] as f32,
                    v[1] as f32,
                    v[2] as f32,
                    v[3] as f32,
                )));
            }
        }
        Ok(None)
    };

    let mut vecs: Vec<usd_gf::Vec4f> = Vec::new();
    if let Ok(list) = obj.cast::<PyList>() {
        let n = list.len();
        if n == 0 {
            return Ok(None);
        }
        for i in 0..n {
            let item = list.get_item(i)?;
            let Some(v) = push_elem(item)? else {
                return Ok(None);
            };
            vecs.push(v);
        }
        return Ok(Some(Value::from_no_hash(vecs)));
    }
    Ok(None)
}

/// `[int, ...]` → `VtIntArray` or `VtInt64Array` in [`Value`] (uses `i64` storage when
/// any element is outside `i32` — matches ids and large integer metadata).
fn seq_to_i32_vec_value(obj: &Bound<'_, PyAny>) -> PyResult<Option<Value>> {
    let mut nums: Vec<i64> = Vec::new();
    if let Ok(list) = obj.cast::<PyList>() {
        let count = list.len();
        if count == 0 {
            return Ok(None);
        }
        for i in 0..count {
            let item = list.get_item(i)?;
            let iv: i64 = match item.extract() {
                Ok(v) => v,
                Err(_) => return Ok(None),
            };
            nums.push(iv);
        }
        return Ok(Some(int_slice_to_value(&nums)));
    }
    if let Ok(tuple) = obj.cast::<PyTuple>() {
        let count = tuple.len();
        if count == 0 {
            return Ok(None);
        }
        for i in 0..count {
            let item = tuple.get_item(i)?;
            let iv: i64 = match item.extract() {
                Ok(x) => x,
                Err(_) => return Ok(None),
            };
            nums.push(iv);
        }
        return Ok(Some(int_slice_to_value(&nums)));
    }
    Ok(None)
}

fn int_slice_to_value(nums: &[i64]) -> Value {
    if nums
        .iter()
        .all(|&x| x >= i64::from(i32::MIN) && x <= i64::from(i32::MAX))
    {
        let vec: Vec<i32> = nums.iter().map(|&x| x as i32).collect();
        return Value::from(vec);
    }
    Value::from_no_hash(Array::<i64>::from(nums.to_vec()))
}

fn py_dict_to_dict(d: &Bound<'_, PyDict>) -> PyResult<Dictionary> {
    let mut dict = Dictionary::new();
    for (k, v) in d.iter() {
        let key: String = k
            .extract()
            .map_err(|_| PyTypeError::new_err("VtDictionary keys must be strings"))?;
        dict.insert_value(key, py_to_value(&v)?);
    }
    Ok(dict)
}

pub(crate) fn value_to_py(py: Python<'_>, v: &Value) -> PyResult<Py<PyAny>> {
    if v.is_empty() {
        return Ok(py.None());
    }
    if let Some(b) = v.get::<bool>() {
        return Ok((*b).into_pyobject(py)?.to_owned().into_any().unbind());
    }
    if let Some(i) = v.get::<i32>() {
        return Ok((*i).into_pyobject(py)?.into_any().unbind());
    }
    if let Some(i) = v.get::<i64>() {
        return Ok((*i).into_pyobject(py)?.into_any().unbind());
    }
    if let Some(u) = v.get::<u64>() {
        return Ok((*u).into_pyobject(py)?.into_any().unbind());
    }
    if let Some(x) = v.get::<f64>() {
        return Ok((*x).into_pyobject(py)?.into_any().unbind());
    }
    if let Some(x) = v.get::<f32>() {
        return Ok((*x as f64).into_pyobject(py)?.into_any().unbind());
    }
    if let Some(s) = v.get::<String>() {
        return Ok(s.as_str().into_pyobject(py)?.into_any().unbind());
    }
    if let Some(t) = v.get::<usd_tf::Token>() {
        return Ok(t.to_string().into_pyobject(py)?.into_any().unbind());
    }
    if let Some(d) = v.get::<usd_vt::Dictionary>() {
        return dict_to_py(py, d);
    }
    if let Some(list) = v.get::<Vec<Value>>() {
        let py_list = PyList::empty(py);
        for item in list {
            py_list.append(value_to_py(py, item)?)?;
        }
        return Ok(py_list.into_any().unbind());
    }
    Ok(py.None())
}

/// Python-facing `VtDictionary` — wraps `Dictionary` and round-trips as Python dict.
#[pyclass(skip_from_py_object, name = "Dictionary", module = "pxr.Vt")]
#[derive(Clone, Default)]
pub struct PyDictionary {
    inner: Dictionary,
}

#[pymethods]
impl PyDictionary {
    #[new]
    #[pyo3(signature = (d = None))]
    fn new(d: Option<&Bound<'_, PyDict>>) -> PyResult<Self> {
        Ok(Self {
            inner: match d {
                Some(pd) => py_dict_to_dict(pd)?,
                None => Dictionary::new(),
            },
        })
    }

    #[pyo3(name = "AsDict")]
    fn as_dict(&self, py: Python<'_>) -> PyResult<Py<PyAny>> {
        dict_to_py(py, &self.inner)
    }

    fn __len__(&self) -> usize {
        self.inner.len()
    }

    fn __repr__(&self, py: Python<'_>) -> PyResult<String> {
        Ok(format!(
            "Vt.Dictionary({})",
            dict_to_py(py, &self.inner)?.bind(py)
        ))
    }
    fn __str__(&self, py: Python<'_>) -> PyResult<String> {
        Ok(format!("{}", dict_to_py(py, &self.inner)?.bind(py)))
    }

    fn __getitem__(&self, py: Python<'_>, key: &str) -> PyResult<Py<PyAny>> {
        self.inner
            .get(key)
            .ok_or_else(|| pyo3::exceptions::PyKeyError::new_err(key.to_owned()))
            .and_then(|v| value_to_py(py, v))
    }

    fn __setitem__(&mut self, key: &str, value: &Bound<'_, PyAny>) -> PyResult<()> {
        self.inner.insert_value(key.to_owned(), py_to_value(value)?);
        Ok(())
    }

    fn __contains__(&self, key: &str) -> bool {
        self.inner.contains_key(key)
    }
    fn __eq__(&self, other: &Self) -> bool {
        self.inner == other.inner
    }
    fn __ne__(&self, other: &Self) -> bool {
        self.inner != other.inner
    }

    fn keys(&self) -> Vec<String> {
        self.inner.keys().map(|k| k.clone()).collect()
    }
}

