/// Register all `pxr.Vt` classes.
pub fn register(py: Python<'_>, m: &Bound<'_, PyModule>) -> PyResult<()> {
    let _ = py;

    m.add_class::<PyValue>()?;
    // Alias: Vt.Value = Vt._ValueWrapper (matches C++ OpenUSD convention)
    m.setattr("Value", m.getattr("_ValueWrapper")?)?;
    m.add_class::<PyDictionary>()?;

    // Scalar arrays
    m.add_class::<PyBoolArray>()?;
    m.add_class::<PyUCharArray>()?;
    m.add_class::<PyShortArray>()?;
    m.add_class::<PyUShortArray>()?;
    m.add_class::<PyIntArray>()?;
    m.add_class::<PyUIntArray>()?;
    m.add_class::<PyInt64Array>()?;
    m.add_class::<PyUInt64Array>()?;
    m.add_class::<PyFloatArray>()?;
    m.add_class::<PyDoubleArray>()?;
    m.add_class::<PyHalfArray>()?;

    // String / Token arrays
    m.add_class::<PyStringArray>()?;
    m.add_class::<PyTokenArray>()?;

    // Vec arrays
    m.add_class::<PyVec2fArray>()?;
    m.add_class::<PyVec3fArray>()?;
    m.add_class::<PyVec4fArray>()?;
    m.add_class::<PyVec2dArray>()?;
    m.add_class::<PyVec3dArray>()?;
    m.add_class::<PyVec4dArray>()?;
    m.add_class::<PyVec2iArray>()?;
    m.add_class::<PyVec3iArray>()?;
    m.add_class::<PyVec4iArray>()?;

    // Matrix arrays
    m.add_class::<PyMatrix4dArray>()?;
    m.add_class::<PyMatrix4fArray>()?;

    // Iterators (must be registered so PyO3 can handle iterator protocol)
    m.add_class::<VtBoolIter>()?;
    m.add_class::<VtI8Iter>()?;
    m.add_class::<VtU8Iter>()?;
    m.add_class::<VtI16Iter>()?;
    m.add_class::<VtU16Iter>()?;
    m.add_class::<VtI32Iter>()?;
    m.add_class::<VtU32Iter>()?;
    m.add_class::<VtI64Iter>()?;
    m.add_class::<VtU64Iter>()?;
    m.add_class::<VtF32Iter>()?;
    m.add_class::<VtF64Iter>()?;
    m.add_class::<VtStringIter>()?;

    m.add_class::<PyIntArrayEdit>()?;
    m.add_class::<PyStringArrayEdit>()?;
    m.add_class::<PyFloatArrayEdit>()?;
    m.add_class::<PyIntArrayEditBuilder>()?;

    m.setattr("Bool", m.getattr("_ValueWrapper")?.getattr("Bool")?)?;
    m.setattr("UChar", m.getattr("_ValueWrapper")?.getattr("UChar")?)?;
    m.setattr("Short", m.getattr("_ValueWrapper")?.getattr("Short")?)?;
    m.setattr("UShort", m.getattr("_ValueWrapper")?.getattr("UShort")?)?;
    m.setattr("Int", m.getattr("_ValueWrapper")?.getattr("Int")?)?;
    m.setattr("UInt", m.getattr("_ValueWrapper")?.getattr("UInt")?)?;
    m.setattr("Long", m.getattr("_ValueWrapper")?.getattr("Long")?)?;
    m.setattr("Int64", m.getattr("_ValueWrapper")?.getattr("Int64")?)?;
    m.setattr("ULong", m.getattr("_ValueWrapper")?.getattr("ULong")?)?;
    m.setattr("UInt64", m.getattr("_ValueWrapper")?.getattr("UInt64")?)?;
    m.setattr("Float", m.getattr("_ValueWrapper")?.getattr("Float")?)?;
    m.setattr("Double", m.getattr("_ValueWrapper")?.getattr("Double")?)?;
    m.setattr("Half", m.getattr("_ValueWrapper")?.getattr("Half")?)?;
    m.setattr("Token", m.getattr("_ValueWrapper")?.getattr("Token")?)?;

    m.add_function(wrap_pyfunction!(_test_ValueTypeName, m)?)?;
    m.add_function(wrap_pyfunction!(_test_Ident, m)?)?;
    m.add_function(wrap_pyfunction!(_test_Str, m)?)?;
    m.add_function(wrap_pyfunction!(_ReturnDictionary, m)?)?;
    m.add_function(wrap_pyfunction!(_DictionaryArrayIdent, m)?)?;
    m.add_function(wrap_pyfunction!(_test_ValueRefFromPython, m)?)?;

    Ok(())
}

